const item = $input.first();
let url = item.json.web || '';

if (!url || typeof url !== 'string' || url.trim() === '') {
  return [{ json: { error: 'URL no válida', original: url } }];
}

url = url.trim();
if (!url.match(/^https?:\/\//i)) {
  url = 'https://' + url;
}
url = url.replace(/^http:\/\//i, 'https://');
if (!url.endsWith('/')) {
  url += '/';
}

return [{ json: { cleanUrl: url, originalUrl: item.json.web } }];

// Obtener HTML
const input = $input.first().json;
let html = '';

if (input.htmlContent && typeof input.htmlContent === 'string') {
  html = input.htmlContent;
} else if (input.data && typeof input.data === 'string') {
  html = input.data;
} else if (typeof input === 'string') {
  html = input;
}

if (!html || html.trim() === '' || html === '{}' || html === 'undefined') {
  return [{
    json: {
      cleanText: '',
      coloresPrincipales: [],
      colorPrimario: '#e65c00',
      colorSecundario: '#f9d423',
      colorAccento: '#ff6b35',
      error: 'No se pudo obtener HTML de la web',
      correo: input.correo || '',
      web: input.web || '',
      nombreLocal: input.nombreLocal || ''
    }
  }];
}

// Limpieza del texto visible
const cleanText = html
  .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, '')
  .replace(/<\/?[^>]+(>|$)/g, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 4000);

// Extracción de colores HEX
const coloresEncontrados = new Set();
const hexMatches = html.match(/#([0-9a-fA-F]{3}){1,2}\b/g) || [];
hexMatches.forEach(color => coloresEncontrados.add(color.toLowerCase()));

const rgbMatches = html.match(/rgba?\s*\(\s*\d{1,3}\s*,\s*\d{1,3}\s*,\s*\d{1,3}(?:\s*,\s*[\d.]+)?\s*\)/gi) || [];
rgbMatches.forEach(rgb => {
  const match = rgb.match(/(\d{1,3})\s*,\s*(\d{1,3})\s*,\s*(\d{1,3})/);
  if (match) {
    const hex = '#' + [match[1], match[2], match[3]]
      .map(x => parseInt(x).toString(16).padStart(2, '0'))
      .join('');
    coloresEncontrados.add(hex.toLowerCase());
  }
});

const coloresUtiles = Array.from(coloresEncontrados).filter(color => {
  if (!color.startsWith('#') || color.length < 4) return false;
  let hex = color.slice(1);
  if (hex.length === 3) hex = hex[0]+hex[0]+hex[1]+hex[1]+hex[2]+hex[2];
  const r = parseInt(hex.slice(0,2),16);
  const g = parseInt(hex.slice(2,4),16);
  const b = parseInt(hex.slice(4,6),16);
  const brightness = (r*299 + g*587 + b*114) / 1000;
  return brightness > 30 && brightness < 240;
});

const coloresPrincipales = coloresUtiles.slice(0, 5);
const colorPrimario = coloresPrincipales[0] || '#e65c00';
const colorSecundario = coloresPrincipales[1] || '#f9d423';
const colorAccento = coloresPrincipales[2] || '#ff6b35';

return [{
  json: {
    cleanText,
    coloresPrincipales,
    colorPrimario,
    colorSecundario,
    colorAccento,
    correo: input.correo || '',
    web: input.web || '',
    nombreLocal: input.nombreLocal || ''
  }
}];

